+    #[test]
+    fn test_style_cache_with_capacity() {
+        use syntect::highlighting::Color as SynColor;
+
+        let mut cache = StyleCache::with_capacity(5);
+        assert_eq!(cache.capacity(), 5);
+        assert!(cache.is_empty());
+
+        // Add 5 styles (to capacity)
+        for i in 0..5 {
+            let style = SynStyle {
+                foreground: SynColor {
+                    r: i as u8,
+                    g: 0,
+                    b: 0,
+                    a: 255,
+                },
+                background: SynColor {
+                    r: 0,
+                    g: 0,
+                    b: 0,
+                    a: 0,
+                },
